`timescale 1ns/1ps
module adder8_tb;
  reg [7:0] a,b; reg cin; wire [7:0] sum; wire cout; integer i,errors=0; reg [8:0] exp;
  adder8 dut(.a(a),.b(b),.cin(cin),.sum(sum),.cout(cout));
  initial begin $dumpfile("adder8_tb.vcd"); $dumpvars(0, adder8_tb); end
  initial begin
    for(i=0;i<300;i=i+1) begin
      a=$random; b=$random; cin=$random; #1; exp=a+b+cin;
      if({cout,sum}!==exp) begin errors=errors+1;
        $display("FAIL a=%0d b=%0d cin=%b got=%0d exp=%0d",a,b,cin,{cout,sum},exp); end
    end
    if(errors==0) $display("TEST PASSED"); else $display("TEST FAILED (%0d errors)",errors);
    $finish;
  end
endmodule
